 53	const envoyTabs = ['clusters', 'listeners', 'routes', 'bootstrap', 'config', 'metrics'];
 54	const tabName = 'envoyTab';
 55	const defaultTab = 'clusters';
 56	
 57	export type ResourceSorts = { [resource: string]: ISortBy };
 58	
 59	type ReduxProps = {
 60	  kiosk: string;
 61	  namespaces: Namespace[];
 62	  theme: string;
 63	};
 64	
 65	type EnvoyDetailsProps = ReduxProps & {
 66	  lastRefreshAt: TimeInMilliseconds;
 67	  namespace: string;
 68	  workload: Workload;
 69	};
