 71	type EnvoyDetailsState = {
 72	  activeKey: number;
 73	  config: EnvoyProxyDump;
 74	  fetch: boolean;
 75	  pod: Pod;
 76	  resource: string;
 77	  tabHeight: number;
 78	  tableSortBy: ResourceSorts;
 79	};
 80	
 81	const fullHeightStyle = kialiStyle({
 82	  height: '100%'
 83	});
