 85	class EnvoyDetailsComponent extends React.Component<EnvoyDetailsProps, EnvoyDetailsState> {
 86	  aceEditorRef: React.RefObject<AceEditor>;
 87	
 88	  constructor(props: EnvoyDetailsProps) {
 89	    super(props);
 90	
 91	    this.aceEditorRef = React.createRef();
 92	
 93	    this.state = {
 94	      pod: this.sortedPods()[0],
 95	      config: {},
 96	      tabHeight: 300,
 97	      fetch: true,
 98	      activeKey: envoyTabs.indexOf(activeTab(tabName, defaultTab)),
 99	      resource: activeTab(tabName, defaultTab),
100	      tableSortBy: {
101	        clusters: {
102	          index: 0,
103	          direction: 'asc'
104	        },
105	        listeners: {
106	          index: 0,
107	          direction: 'asc'
108	        },
109	        routes: {
110	          index: 0,
111	          direction: 'asc'
112	        }
113	      }
114	    };
115	  }
116	
117	  componentDidMount(): void {
118	    this.fetchContent();
119	  }
120	
121	  componentDidUpdate(_prevProps: EnvoyDetailsProps, prevState: EnvoyDetailsState): void {
122	    const currentTabIndex = envoyTabs.indexOf(activeTab(tabName, defaultTab));
123	
124	    if (this.state.pod.name !== prevState.pod.name || this.state.resource !== prevState.resource) {
125	      this.fetchContent();
126	
127	      if (currentTabIndex !== this.state.activeKey) {
128	        this.setState({ activeKey: currentTabIndex });
129	      }
130	    }
131	  }
132	
133	  envoyHandleTabClick = (_event: React.MouseEvent, tabIndex: string | number): void => {
134	    const resourceIdx: number = +tabIndex;
135	    const targetResource: string = resources[resourceIdx];
136	
137	    if (targetResource !== this.state.resource) {
138	      this.setState({
139	        config: {},
140	        fetch: true,
141	        resource: targetResource,
142	        activeKey: resourceIdx
143	      });
144	
145	      const mainTab = new URLSearchParams(location.getSearch()).get(workloadTabName) ?? workloadDefaultTab;
146	      const urlParams = new URLSearchParams(location.getSearch());
147	      urlParams.set(tabName, targetResource);
148	      urlParams.set(workloadTabName, mainTab);
149	      router.navigate(`${location.getPathname()}?${urlParams.toString()}`);
150	    }
151	  };
152	
153	  fetchEnvoyProxyResourceEntries = (resource: string): void => {
154	    API.getPodEnvoyProxyResourceEntries(
155	      this.props.namespace,
156	      this.state.pod.name,
157	      resource,
158	      this.props.workload.cluster
159	    )
160	      .then(resultEnvoyProxy => {
161	        this.setState({
162	          config: resultEnvoyProxy.data,
163	          fetch: false
164	        });
165	      })
166	      .catch(error => {
167	        AlertUtils.addError(`Could not fetch envoy config ${resource} entries for ${this.state.pod.name}.`, error);
168	      });
169	  };
170	
171	  fetchEnvoyProxy = (): void => {
172	    API.getPodEnvoyProxy(this.props.namespace, this.state.pod.name, this.props.workload.cluster)
173	      .then(resultEnvoyProxy => {
174	        this.setState({
175	          config: resultEnvoyProxy.data,
176	          fetch: false
177	        });
178	      })
179	      .catch(error => {
180	        AlertUtils.addError(`Could not fetch envoy config for ${this.state.pod.name}.`, error);
181	      });
182	  };
183	
184	  fetchContent = (): void => {
185	    if (this.state.fetch === true) {
186	      if (this.state.resource === 'config') {
187	        this.fetchEnvoyProxy();
188	      } else {
189	        this.fetchEnvoyProxyResourceEntries(this.state.resource);
190	      }
191	    }
192	  };
193	
194	  setPod = (podName: string): void => {
195	    const podIdx: number = +podName;
196	    const targetPod: Pod = this.sortedPods()[podIdx];
197	
198	    if (targetPod.name !== this.state.pod.name) {
199	      this.setState({
200	        config: {},
201	        pod: targetPod,
202	        fetch: true
203	      });
204	    }
205	  };
206	
207	  sortedPods = (): Pod[] => {
208	    return this.props.workload.pods.sort((p1: Pod, p2: Pod) => (p1.name >= p2.name ? 1 : -1));
209	  };
210	
211	  onSort = (tab: string, index: number, direction: SortByDirection): void => {
212	    if (this.state.tableSortBy[tab].index !== index || this.state.tableSortBy[tab].direction !== direction) {
213	      let tableSortBy = this.state.tableSortBy;
214	      tableSortBy[tab].index = index;
215	      tableSortBy[tab].direction = direction;
216	      this.setState({
217	        tableSortBy: tableSortBy
218	      });
219	    }
220	  };
221	
222	  editorContent = (): string => JSON.stringify(this.state.config, null, '  ');
223	
224	  onCopyToClipboard = (_text: string, _result: boolean): void => {
225	    const editor = this.aceEditorRef.current!['editor'];
226	
227	    if (editor) {
228	      editor.selectAll();
229	    }
230	  };
231	
232	  showEditor = (): boolean => {
233	    return this.state.resource === 'config' || this.state.resource === 'bootstrap';
234	  };
235	
236	  showMetrics = (): boolean => {
237	    return this.state.resource === 'metrics';
238	  };
239	
240	  getEnvoyMetricsDashboardRef = (): DashboardRef | undefined => {
241	    let envoyDashboardRef: DashboardRef | undefined = undefined;
242	    this.props.workload.runtimes.forEach(runtime => {
243	      runtime.dashboardRefs.forEach(dashboardRef => {
244	        if (dashboardRef.template === 'envoy') {
245	          envoyDashboardRef = dashboardRef;
246	        }
247	      });
248	    });
249	    return envoyDashboardRef;
250	  };
251	
252	  isLoadingConfig = (): boolean => {
253	    return Object.keys(this.state.config).length < 1;
254	  };
255	
256	  onRouteLinkClick = (): void => {
257	    this.setState({
258	      config: {},
259	      fetch: true,
260	      resource: 'routes',
261	      activeKey: 2 // Routes index
262	    });
263	
264	    // Forcing to regenerate the active filters
265	    FilterSelected.resetFilters();
266	  };
267	
268	  render(): React.ReactNode {
269	    const builder = SummaryTableBuilder(
270	      this.state.resource,
271	      this.state.config,
272	      this.state.tableSortBy,
273	      this.props.namespaces,
274	      this.props.namespace,
275	      this.onRouteLinkClick,
276	      this.props.kiosk,
277	      this.props.workload.name
278	    );
279	
280	    const SummaryWriterComp = builder[0];
281	    const summaryWriter = builder[1];
282	    const height = this.state.tabHeight - 226;
283	    const appLabelName = getAppLabelName(this.props.workload.labels);
284	    const verLabelName = getVersionLabelName(this.props.workload.labels);
285	    const app = appLabelName ? this.props.workload.labels[appLabelName] : '';
286	    const version = verLabelName ? this.props.workload.labels[verLabelName] : '';
287	    const envoyMetricsDashboardRef = this.getEnvoyMetricsDashboardRef();
288	    let filteredEnvoyTabs = envoyTabs;
289	
290	    if (!envoyMetricsDashboardRef) {
291	      filteredEnvoyTabs = envoyTabs.slice(0, envoyTabs.length - 1);
292	    }
293	
294	    const tabs = filteredEnvoyTabs.map((value, index) => {
295	      const title = `${value.charAt(0).toUpperCase()}${value.slice(1)}`;
296	
297	      return (
298	        <Tab key={`tab_${value}`} eventKey={index} title={title}>
299	          <Card className={fullHeightStyle}>
300	            <CardBody>
301	              {this.showEditor() ? (
302	                <div className={fullHeightStyle}>
303	                  <div style={{ marginBottom: '1.25rem' }}>
304	                    <div key="service-icon" className={iconStyle}>
305	                      <PFBadge badge={PFBadges.Pod} position={TooltipPosition.top} />
306	                    </div>
307	
308	                    <ToolbarDropdown
309	                      id="envoy_pods_list"
310	                      tooltip="Display envoy config for the selected pod"
311	                      handleSelect={key => this.setPod(key)}
312	                      value={this.state.pod.name}
313	                      label={this.state.pod.name}
314	                      options={this.props.workload.pods.map((pod: Pod) => pod.name).sort()}
315	                    />
316	
317	                    <Tooltip key="copy_config" position="top" content="Copy config dump to clipboard">
318	                      <CopyToClipboard onCopy={this.onCopyToClipboard} text={this.editorContent()}>
319	                        <Button variant={ButtonVariant.link} className={copyButtonStyle} isInline>
320	                          <KialiIcon.Copy />
321	                          <span>Copy</span>
322	                        </Button>
323	                      </CopyToClipboard>
324	                    </Tooltip>
325	                  </div>
326	
327	                  <AceEditor
328	                    ref={this.aceEditorRef}
329	                    mode="yaml"
330	                    theme={this.props.theme === Theme.DARK ? 'twilight' : 'eclipse'}
331	                    width={'100%'}
332	                    height={`${height.toString()}px`}
333	                    className={istioAceEditorStyle}
334	                    wrapEnabled={true}
335	                    readOnly={true}
336	                    setOptions={aceOptions ?? { foldStyle: 'markbegin' }}
337	                    value={this.editorContent()}
338	                  />
339	                </div>
340	              ) : this.showMetrics() && envoyMetricsDashboardRef ? (
341	                <CustomMetrics
342	                  app={app}
343	                  appLabelName={appLabelName}
344	                  data-test="envoy-metrics-component"
345	                  embedded={true}
346	                  height={this.state.tabHeight - 40 - 24 + 13}
347	                  lastRefreshAt={this.props.lastRefreshAt}
348	                  namespace={this.props.namespace}
349	                  template={envoyMetricsDashboardRef.template}
350	                  version={version}
351	                  workload={this.props.workload!.name}
352	                />
353	              ) : (
354	                <SummaryWriterComp
355	                  writer={summaryWriter}
356	                  sortBy={this.state.tableSortBy}
357	                  onSort={this.onSort}
358	                  pod={this.state.pod.name}
359	                  pods={this.props.workload.pods.map(pod => pod.name)}
360	                  setPod={this.setPod}
361	                />
362	              )}
363	            </CardBody>
364	          </Card>
365	        </Tab>
366	      );
367	    });
368	
369	    return (
370	      <RenderComponentScroll onResize={height => this.setState({ tabHeight: height })} containTable>
371	        <Tabs
372	          id="envoy-details"
373	          className={subTabStyle}
374	          activeKey={this.state.activeKey}
375	          onSelect={this.envoyHandleTabClick}
376	          mountOnEnter={true}
377	          unmountOnExit={true}
378	        >
379	          {tabs}
380	        </Tabs>
381	      </RenderComponentScroll>
382	    );
383	  }
384	}
385	
386	const mapStateToProps = (state: KialiAppState): ReduxProps => ({
387	  kiosk: state.globalState.kiosk,
388	  namespaces: namespaceItemsSelector(state)!,
389	  theme: state.globalState.theme
390	});
391	
392	export const EnvoyDetails = connect(mapStateToProps)(EnvoyDetailsComponent);

